23: func parseModule(mod *modfile.Require) Module {
24: 	m := Module{Name: mod.Mod.String()}
25: 
26: 	// For each require, access the comment.
27: 	for _, comment := range mod.Syntax.Comments.Suffix {
28: 		owners := strings.Fields(comment.Token)
