108: 			for _, owner := range mod.Owners {
109: 				logger.Println(owner)
110: 				break
111: 			}
112: 		}
113: 		if mod.Indirect == false {
114: 			for _, owner := range mod.Owners {
115: 				owners[owner]++
116: 			}
117: 		}
118: 	}
119: 	if *allOwners {
120: 		for owner, n := range owners {
121: 			if *count {
122: 				logger.Println(owner, n)
123: 			} else {
124: 				logger.Println(owner)
125: 			}
126: 		}
127: 	}
128: 	return nil
